import { callMcpSkill, callMcpSkillsParallel } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

export async function main() {
  const intent = "Determine whether a specific yes/no Polymarket market is efficiently priced right now by checking vig, spread, and vig-adjusted true implied probabilities.";

  const executionPlan = {
    intent,
    strictValidation: true,
    requiresBinaryEfficiencyPath: true,
    requiresDirectInstruments: true,
    requiresCrossVenueCoverage: false,
    namedVenues: [],
    status: "blocked_pending_identifier",
    stopReason: "The specific yes/no market was not provided, so the efficiency check cannot be grounded yet.",
    requiredUserAction: "Provide the exact market title, slug, or conditionId.",
    probeDecisionExecute: {
      probe: {
        rule: "Do not run broad discovery before a direct market identifier is available.",
        allowedInputs: ["exact market title", "slug", "conditionId"],
        disallowedAsPrimaryPath: ["broad trending search", "proxy market selection", "category-wide browsing"],
      },
      decide: {
        rule: "If the market identifier is present, skip generic browsing and go directly to the dedicated efficiency/vig method.",
        selectionPolicy: "Use the exact resolved market only; do not substitute a related market.",
      },
      execute: {
        rule: "Call check_market_efficiency directly on the exact slug or conditionId.",
        outputsNeeded: ["marketEfficiency.vig", "marketEfficiency.sumOfOutcomes", "outcomes", "trueProbabilities", "trueProbabilitiesPercent"],
      },
    },
    readBatchPolicy: {
      rule: "If and only if the user later provides an ambiguous market title, perform a single shortlist-first discovery step, then analyze locally.",
      parallelism: "Only batch independent read-only calls across different tools/endpoints with callMcpSkillsParallel.",
      sameEndpointRule: "Do not use Promise.all or Promise.allSettled for same-endpoint exploration.",
      shortlistRule: "Use one broad discovery call, then deterministic semantic targeting before any follow-up data call.",
      semanticTargeting: {
        tool: "pickTopSemanticCandidates",
        target: "the exact yes/no market the user meant",
        requiredTerms: ["market", "yes/no"],
        avoidTerms: ["proxy", "related", "category"],
      },
    },
    fallbackIfAmbiguous: {
      branch: "single_shortlist_then_direct_efficiency",
      steps: [
        "Use one discovery call to resolve the exact market identifier.",
        "Rank candidates locally with pickTopSemanticCandidates.",
        "Select the highest-confidence exact match only.",
        "Call check_market_efficiency on that exact market.",
      ],
      stopCondition: "If no exact market can be resolved, return missingData instead of fabricating probabilities.",
    },
    localAnalysis: {
      afterReadBatchOnly: true,
      calculations: [
        "Use marketEfficiency.vig and marketEfficiency.sumOfOutcomes to judge whether the market is efficiently priced.",
        "Treat sumOfOutcomes > 1.0 as overround from vig/spread/fees.",
        "Use trueProbabilities and trueProbabilitiesPercent as the adjusted implied probabilities after overround.",
      ],
      packaging: "Keep filtering, ranking, and response formatting serial after the read batch completes.",
    },
    returnShape: {
      ifResolved: {
        market: "exact resolved market",
        efficiency: "efficient | not efficient",
        vig: "from tool output",
        spread: "from tool output",
        trueProbabilities: "from tool output",
        trueProbabilitiesPercent: "from tool output",
      },
      ifUnresolved: {
        missingData: ["exact market title | slug | conditionId"],
        attemptedBranches: ["direct identifier request only"],
        stopReason: "Cannot run binary efficiency analysis without a concrete market.",
      },
    },
  };

  return {
    executionPlan,
    readyForExecution: false,
    requiredUserInput: "Please send the exact yes/no market title, slug, or conditionId.",
  };
}

import { callMcpSkill } from "@/lib/ai/skills/mcp";

const POLYMARKET_TOOL_ID = "294100e8-c648-4e5f-a254-95a14b56e398";

export async function main(input = {}) {
  const marketIdentifier =
    input.conditionId || input.slug || input.marketQuery || input.marketTitle || "";

  const executionPlan = {
    intent:
      "Determine whether a specific yes/no Polymarket market is efficiently priced right now by checking vig, spread, and vig-adjusted true implied probabilities.",
    strictValidation: true,
    requiresBinaryEfficiencyPath: true,
    requiresDirectInstruments: true,
    requiresCrossVenueCoverage: false,
    status: marketIdentifier ? "ready_for_probe" : "blocked_pending_identifier",
    stopReason: marketIdentifier
      ? null
      : "The specific yes/no market was not provided, so the efficiency check cannot be grounded yet.",
    requiredUserAction: marketIdentifier
      ? null
      : "Provide the exact market title, slug, or conditionId.",
  };

  if (!marketIdentifier) {
    return {
      executionPlan,
      readyForExecution: false,
      needsDifferentTools: false,
      requiredUserInput: "Please send the exact yes/no market title, slug, or conditionId.",
      missingData: ["exact market title | slug | conditionId"],
      attemptedBranches: ["direct identifier request only"],
      stopReason: "Cannot run binary efficiency analysis without a concrete market.",
    };
  }

  let result;
  try {
    result = await callMcpSkill({
      toolId: POLYMARKET_TOOL_ID,
      toolName: "check_market_efficiency",
      args: input.conditionId
        ? { conditionId: input.conditionId }
        : { slug: input.slug || input.marketTitle || input.marketQuery },
    });
  } catch (error) {
    return {
      executionPlan,
      readyForExecution: false,
      needsDifferentTools: true,
      error: error?.message || String(error),
      stopReason: "Authorized tools could not complete the efficiency check.",
    };
  }

  // Correctly parse the actual tool output schema:
  // {
  //   conditionId,
  //   market,
  //   outcomes: [{ name, price, tokenId, impliedProbability, impliedProbabilityPercent }],
  //   marketEfficiency: { vig, vigBps, sumOfOutcomes, ... }
  // }
  const market = result?.market || input.marketTitle || input.slug || input.conditionId || "Unknown market";
  const outcomes = Array.isArray(result?.outcomes) ? result.outcomes : [];
  const marketEfficiency = result?.marketEfficiency || {};

  const vig = marketEfficiency.vig ?? null;
  const spread = marketEfficiency.spread ?? marketEfficiency.spreadBps ?? null;
  const sumOfOutcomes = marketEfficiency.sumOfOutcomes ?? null;

  const trueProbabilities = outcomes.map((o) => ({
    name: o?.name,
    probability: o?.impliedProbability ?? null,
  }));

  const trueProbabilitiesPercent = outcomes.map((o) => ({
    name: o?.name,
    probabilityPercent: o?.impliedProbabilityPercent ?? null,
  }));

  const efficiency =
    typeof sumOfOutcomes === "number"
      ? sumOfOutcomes <= 1.01
        ? "efficient"
        : "not efficient"
      : vig !== null
      ? vig <= 0.01
        ? "efficient"
        : "not efficient"
      : "unknown";

  return {
    executionPlan,
    readyForExecution: true,
    needsDifferentTools: false,
    market,
    conditionId: result?.conditionId || input.conditionId || null,
    efficiency,
    vig,
    spread,
    sumOfOutcomes,
    outcomes,
    trueProbabilities,
    trueProbabilitiesPercent,
    fetchedAt: result?.fetchedAt || null,
    recommendation: result?.recommendation || null,
  };
}

